import Header from "../components/Header";

function StockMarket() {
  return (
    <div style={styles.page}>
      <Header />
      <main style={styles.main}>
        <h1 style={styles.title}>Stock Market</h1>
        <p style={styles.subtitle}>Coming soon.</p>
      </main>
    </div>
  );
}

const BG = "#1A1A1A";
const TEXT = "#F9F9F9";

const styles = {
  page: {
    minHeight: "100vh",
    backgroundColor: BG,
    color: TEXT,
    fontFamily: "'Segoe UI', sans-serif",
  },
  main: {
    maxWidth: "78.125rem",
    margin: "0 auto",
    padding: "3.125rem 1.25rem",
  },
  title: {
    margin: "0 0 0.5rem",
    fontSize: "2rem",
    fontWeight: "700",
  },
  subtitle: {
    color: "#666",
    fontSize: "1rem",
  },
};

export default StockMarket;
